   265→            $file = preg_replace('{^'.preg_quote($this->basePath).'}', '', $file);
   266→        }
   267→
   268→        $data = [
   269→            'class' => Utils::getClass($e),
   270→            'message' => $e->getMessage(),
   271→            'code' => (int) $e->getCode(),
   272→            'file' => $file.':'.$e->getLine(),
   273→        ];
